# quality/freshness_check.py
# Freshness and completeness checks for RAG source documents

from dataclasses import dataclass, field
from datetime import datetime, timedelta, timezone
from typing import Any

# Category-level configuration: max age in days and required fields
DOC_QUALITY_CONFIG: dict[str, dict] = {
    "regulatory": {
        "max_age_days": 30,
        "required_fields": ["title", "effective_date", "domain", "author", "source_url"],
        "min_content_chars": 200,
    },
    "policy": {
        "max_age_days": 90,
        "required_fields": ["title", "domain", "author", "source_url"],
        "min_content_chars": 150,
    },
    "reference": {
        "max_age_days": 180,
        "required_fields": ["title", "domain", "source_url"],
        "min_content_chars": 50,
    },
}

@dataclass
class CheckResult:
    doc_id: str
    check_type: str
    passed: bool
    failure_reasons: list[str] = field(default_factory=list)
    checked_at: str = field(
        default_factory=lambda: datetime.now(timezone.utc).isoformat()
    )


def check_freshness(
    doc: dict[str, Any],
    config: dict = DOC_QUALITY_CONFIG,
    now: datetime | None = None,
) -> CheckResult:
    if now is None:
        now = datetime.now(timezone.utc)

    doc_id = doc.get("doc_id", "unknown")
    category = doc.get("category", "reference")
    cfg = config.get(category, config["reference"])
    max_age = cfg["max_age_days"]

    modified_str = doc.get("modified_at")
    if not modified_str:
        return CheckResult(
            doc_id=doc_id,
            check_type="freshness",
            passed=False,
            failure_reasons=["missing modified_at timestamp"],
        )

    modified = datetime.fromisoformat(modified_str)
    if modified.tzinfo is None:
        modified = modified.replace(tzinfo=timezone.utc)

    age_days = (now - modified).days
    if age_days > max_age:
        return CheckResult(
            doc_id=doc_id,
            check_type="freshness",
            passed=False,
            failure_reasons=[
                f"document age {age_days}d exceeds max {max_age}d for category '{category}'"
            ],
        )

    return CheckResult(doc_id=doc_id, check_type="freshness", passed=True)


def check_completeness(
    doc: dict[str, Any],
    config: dict = DOC_QUALITY_CONFIG,
) -> CheckResult:
    doc_id = doc.get("doc_id", "unknown")
    category = doc.get("category", "reference")
    cfg = config.get(category, config["reference"])

    reasons = []
    for field_name in cfg["required_fields"]:
        val = doc.get(field_name)
        if not val or (isinstance(val, str) and not val.strip()):
            reasons.append(f"missing required field '{field_name}'")

    content = doc.get("content", "")
    if len(content) < cfg["min_content_chars"]:
        reasons.append(
            f"content length {len(content)} < minimum {cfg['min_content_chars']} chars"
        )

    return CheckResult(
        doc_id=doc_id,
        check_type="completeness",
        passed=len(reasons) == 0,
        failure_reasons=reasons,
    )
